const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

// Store player sessions in a secure data store (e.g., encrypted JSON)
const sessions = {};

wss.on('connection', (ws) => {
    console.log('Client connected');

    // Handle incoming messages from clients
    ws.on('message', (message) => {
        try {
            const data = JSON.parse(message);
            if (!data.type || !['build', 'attack', 'move'].includes(data.type)) {
                console.error('Invalid command type');
                return;
            }

            const sessionId = data.sessionId;
            if (!sessions[sessionId]) {
                console.error('Unknown session ID');
                return;
            }

            switch (data.type) {
                case 'build':
                    // Process build command
                    sessions[sessionId].units.push({ type: 'building', position: data.position });
                    break;
                case 'attack':
                    // Process attack command
                    sessions[sessionId].units.forEach((unit, index) => {
                        if (unit.type === 'unit' && unit.position.x === data.targetPosition.x && unit.position.y === data.targetPosition.y) {
                            unit.isAttacking = true;
                            sessions[sessionId].units.splice(index, 1);
                        }
                    });
                    break;
                case 'move':
                    // Process move command
                    sessions[sessionId].units.forEach((unit) => {
                        if (unit.type === 'unit' && unit.position.x === data.position.x && unit.position.y === data.position.y) {
                            unit.isMoving = true;
                        }
                    });
                    break;
            }

            // Broadcast updated game state to all connected clients
            wss.clients.forEach((client) => {
                client.send(JSON.stringify({
                    type: 'update',
                    sessionId,
                    units: sessions[sessionId].units,
                }));
            });
        } catch (error) {
            console.error('Error processing message:', error);
        }
    });

    // Handle disconnections
    ws.on('close', () => {
        console.log('Client disconnected');
    });
});

// Securely store and retrieve player sessions
function getSession(sessionId) {
    return sessions[sessionId];
}

function saveSession(sessionId, sessionData) {
    sessions[sessionId] = sessionData;
}